package com.xda.sa2ration.automation;
import org.junit.Test;import java.util.Arrays;import static org.junit.Assert.*;
public final class AutomationEngineTest {@Test public void highestPriorityMatchingRuleWins(){AutomationRule low=new AutomationRule();low.conditionType=AutomationConditionType.CHARGING;low.operand="true";low.priority=1;AutomationRule high=new AutomationRule();high.conditionType=AutomationConditionType.APPLICATION;high.operand="com.video";high.priority=50;AutomationContext c=new AutomationContext();c.charging=true;c.foregroundPackage="com.video";assertSame(high,new AutomationEngine().select(Arrays.asList(low,high),c));}@Test public void invalidOperandDoesNotCrash(){AutomationRule r=new AutomationRule();r.conditionType=AutomationConditionType.TIME_RANGE;r.operand="invalid";assertFalse(new AutomationEngine().matches(r,new AutomationContext()));}}
